              {
                "name": "Identity",
                "items": [
                  "Proof of Kansas residency",
                  "Photo ID or birth certificate",
                  "Citizenship or immigration status documents"
                ]
              },
              {
                "name": "Medical",
                "items": [
                  "Medicare card (if enrolled)",
                  "Medicaid card (if enrolled)",
                  "Current medication list",
                  "Recent medical records or doctor assessments"
                ]
              }
